1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
14	type Step = { op: "quote"; items: Item[] };
15	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
16	
17	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_BASE_PREMIUM = 60;
22	
23	const sumBasePremiums = (items: Item[]): number =>
24	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
25	
26	const componentGroupSubtotalOf = (group: Item[]): number =>
27	  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);
28	
29	const groupByType = (items: Item[]): Map<string, Item[]> => {
30	  const groups = new Map<string, Item[]>();
31	  for (const item of items) {
32	    const existing = groups.get(item.type) ?? [];
33	    existing.push(item);
34	    groups.set(item.type, existing);
35	  }
36	  return groups;
37	};
38	
39	const componentSubtotalOf = (components: Item[]): number =>
40	  [...groupByType(components).values()].reduce(
41	    (sum, group) => sum + componentGroupSubtotalOf(group),
42	    0,
43	  );
44	
45	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
46	
47	const policyBaseOf = (items: Item[]): number => {
48	  const components = items.filter(isComponent);
49	  const mainItems = items.filter((item) => !isComponent(item));
50	  return sumBasePremiums(mainItems) + componentSubtotalOf(components);
51	};
52	
53	const CURSED_SURCHARGE_RATE = 0.5;
54	
55	const firstInsuranceSurchargeOf = (policyBase: number): number =>
56	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
57	
58	const itemSurchargesOf = (items: Item[]): number =>
59	  items.reduce((sum, item) => sum + (item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0), 0);
60	
61	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
62	
63	const quotePremium = (items: Item[]): number => {
64	  const policyBase = policyBaseOf(items);
65	  const rawPremium =
66	    policyBase + itemSurchargesOf(items) + firstInsuranceSurchargeOf(policyBase) + PROCESSING_FEE;
67	  return roundUpInMHPCOFavor(rawPremium);
68	};
69	
70	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
71	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
72	  return { results };
73	};
